<?php
namespace App\Models;use Illuminate\Database\Eloquent\Factories\HasFactory;use Illuminate\Database\Eloquent\Model;class HuntRewardItem extends Model{use HasFactory;protected $guarded=[];protected $casts=['quantity'=>'integer','item_rarity_id'=>'integer','rarity_roll_metadata'=>'array'];public function reward(){return$this->belongsTo(HuntReward::class,'hunt_reward_id');}public function huntEnemy(){return$this->belongsTo(HuntEnemy::class);}public function item(){return$this->belongsTo(Item::class);}public function itemRarity(){return$this->belongsTo(ItemRarity::class);}public function itemInstances(){return$this->hasMany(ItemInstance::class,'origin_id')->where('origin_type','hunt_reward_item');}}
